-- Nave Data
select FT.ID_FILE_TYPE, FT.TYPE_NAME, FTI.*
from TFM_FILE_TYPE_ISSUER_FIELD FTI
inner join  TFM_FILE_TYPE FT on FTI.ID_FILE_TYPE = FT.ID_FILE_TYPE
where type_name like 'DATA_DUMP_RPT%'

select * from TFM_FILE_TYPE where type_name like 'DATA_DUMP_RPT%'
select * from TFM_FILE_TYPE where type_name like 'DATA_DUMP_RPT_PENALTY_INTEREST'
select * from TFM_FILE_TYPE_ISSUER_FIELD WHERE ID_FILE_TYPE = 221
select ID_FILE_TYPE, 999 as ID_ISSUER, FIELD, IS_VISIBLE, LENGTH from TFM_FILE_TYPE_ISSUER_FIELD WHERE ID_FILE_TYPE = 192 order by ID_FILE_ISSUER_FIELD

---
SELECT
    IFT.ID_ISSUER_FILE_TYPE  IdIssuerFileType,
    IFT.ID_ISSUER            IdIssuer,
    IFT.ID_FILE_TYPE         IdFileType,
    FT.TYPE_NAME,
    IFT.ID_PROCESS           IdProcess,
    IFT.FORMAT               Format,
    IFT.EXTENSION            Extension,
    IFT.ENCODING             Encoding
FROM TBE_PROCESS P
    INNER JOIN TBE_BATCH_PROCESS     BP  ON P.ID_PROCESS   = BP.ID_PROCESS
    INNER JOIN TFM_FILE_TYPE         FT  ON FT.ID_PROCESS  = BP.ID_PROCESS
    INNER JOIN IBC_ISSUER_FILE_TYPE  IFT ON IFT.ID_FILE_TYPE = FT.ID_FILE_TYPE
WHERE IFT.ID_ISSUER = 100

